def extract_pfs_from_text(text: str) -> Dict[str, Any]:
    """Parse BB&T / standard personal financial statement PDF text."""
    facts: Dict[str, Any] = {}
    lines = text.splitlines()

    def _scan_after_label(
        label_pat: str,
        *,
        min_amount: float = 1_000,
        max_lookahead: int = 40,
        exclude: Optional[float] = None,
    ) -> Optional[float]:
        for i, line in enumerate(lines):
            if not re.search(label_pat, line, re.IGNORECASE):
                continue
            for nxt in lines[i + 1 : i + 1 + max_lookahead]:
                cleaned = nxt.strip().replace("$", "").replace(",", "")
                if not cleaned or cleaned == "-":
                    continue
                val = _parse_money(cleaned)
                if val is None or val < min_amount:
                    continue
                if exclude is not None and abs(val - exclude) < 1:
                    continue
                return val
        return None

    assets = _scan_after_label(r"22\.\s*Total of All Assets", min_amount=100_000)
    liabilities = _scan_after_label(
        r"30\.\s*Total Liabilities",
        min_amount=100_000,
        exclude=assets,
    )
    net_worth = _scan_after_label(
        r"31\.\s*Net Worth",
        min_amount=100_000,
        exclude=assets,
    )

    cash = _scan_after_label(r"12\.\s*Cash\s*\(Schedule A\)", min_amount=100)
    if cash is None:
        cash = _scan_after_label(r"Cash\s*\(Schedule A\)", min_amount=100)
    if cash is not None:
        facts["liquid_assets"] = cash
        facts["pfs_cash"] = cash

    mkt = _scan_after_label(
        r"13\.\s*U\.S\. gov't\.\s*and marketable securities",
        min_amount=100,
    )
    if mkt is not None:
        facts["marketable_securities"] = mkt

    if assets is not None:
        facts["total_assets"] = assets
    if liabilities is not None:
        facts["total_liabilities"] = liabilities
    if assets is not None and liabilities is not None:
        facts["net_worth"] = assets - liabilities
    elif net_worth is not None:
        facts["net_worth"] = net_worth

    return facts


def extract_credit_report_fields(text: str) -> Dict[str, Any]:
    """Extract bureau FICO scores from merged tri-merge credit report PDFs."""
    facts: Dict[str, Any] = {}
    bureau_scores: Dict[str, int] = {}

    patterns: Tuple[Tuple[str, str], ...] = (
        ("transunion", r"FICO Risk Score, Classic \(04\)\s*(\d{3})"),
        ("experian", r"Fair Isaac \(v2\)\s*\[\s*(\d{3})\s*\]"),
        ("equifax", r"FICO Classic v5\s+(\d{3})"),
    )
    for bureau, pat in patterns:
        m = re.search(pat, text, re.IGNORECASE)
        if m:
            score = int(m.group(1))
            if 300 <= score < 850:
                bureau_scores[bureau] = score

    if not bureau_scores:
        for m in re.finditer(r"(\d{3})\s+Factors\s*•", text):
            score = int(m.group(1))
            if 300 <= score <= 850:
                bureau_scores.setdefault(f"bureau_{len(bureau_scores) + 1}", score)

    if bureau_scores:
        facts["bureau_fico_scores"] = bureau_scores
        scores = sorted(bureau_scores.values())
        mid = scores[len(scores) // 2]
        facts["primary_fico_score"] = mid
        facts["credit_score_mention"] = mid
    return facts


